    else:
        return chr(ord('0') + k - 27)

def build_string(k):
    if k == 1:
        return 'a'
    prev = build_string(k - 1)
    return prev + get_char(k) + prev

def solve():
    l1, r1, l2, r2 = map(int, input().split())
    max_k = 30  # Since 2^30-1 is around 1e9, which is sufficient for the constraints
    s = build_string(max_k)
    s1 = s[l1-1:r1]
    s2 = s[l2-1:r2]

    max_len = 0
    len1 = len(s1)
    len2 = len(s2)

    # Create a DP table to store lengths of longest common suffixes
    dp = [[0] * (len2 + 1) for _ in range(len1 + 1)]

    for i in range(1, len1 + 1):
        for j in range(1, len2 + 1):
            if s1[i-1] == s2[j-1]:
                dp[i][j] = dp[i-1][j-1] + 1
                if dp[i][j] > max_len:
                    max_len = dp[i][j]
            else:
                dp[i][j] = 0
